import React, { useState } from 'react';

const FormularioCampesenaCompleto = ({ formData, setFormData }) => {
  const [instructores, setInstructores] = useState([
    {
      tipo: 'Técnico',
      tipo_identificacion: 'CC',
      identificacion: '',
      nombre: '',
      correo: '',
      celular: '',
      programacion: []
    },
    {
      tipo: 'Empresarial',
      tipo_identificacion: 'CC',
      identificacion: '',
      nombre: '',
      correo: '',
      celular: '',
      programacion: []
    },
    {
      tipo: 'Popular',
      tipo_identificacion: 'CC',
      identificacion: '',
      nombre: '',
      correo: '',
      celular: '',
      programacion: []
    }
  ]);

  const agregarMes = (indexInstructor) => {
    const nuevosInstructores = [...instructores];
    if (!nuevosInstructores[indexInstructor].programacion) {
      nuevosInstructores[indexInstructor].programacion = [];
    }
    nuevosInstructores[indexInstructor].programacion.push({
      mes: nuevosInstructores[indexInstructor].programacion.length + 1,
      dias: [],
      horario: {
        hora_inicio: '08:00',
        hora_fin: '17:00'
      }
    });
    setInstructores(nuevosInstructores);
    setFormData({ ...formData, instructores: nuevosInstructores });
  };

  const agregarDia = (indexInstructor, indexMes) => {
    const nuevosInstructores = [...instructores];
    if (!nuevosInstructores[indexInstructor].programacion[indexMes].dias) {
      nuevosInstructores[indexInstructor].programacion[indexMes].dias = [];
    }
    nuevosInstructores[indexInstructor].programacion[indexMes].dias.push('');
    setInstructores(nuevosInstructores);
    setFormData({ ...formData, instructores: nuevosInstructores });
  };

  const eliminarDia = (indexInstructor, indexMes, indexDia) => {
    const nuevosInstructores = [...instructores];
    nuevosInstructores[indexInstructor].programacion[indexMes].dias.splice(indexDia, 1);
    setInstructores(nuevosInstructores);
    setFormData({ ...formData, instructores: nuevosInstructores });
  };

  const actualizarCampo = (indexInstructor, campo, valor) => {
    const nuevosInstructores = [...instructores];
    nuevosInstructores[indexInstructor][campo] = valor;
    setInstructores(nuevosInstructores);
    setFormData({ ...formData, instructores: nuevosInstructores });
  };

  const actualizarCampoProgramacion = (indexInstructor, indexMes, campo, valor) => {
    const nuevosInstructores = [...instructores];
    if (campo.includes('horario.')) {
      const horarioCampo = campo.split('.')[1];
      nuevosInstructores[indexInstructor].programacion[indexMes].horario[horarioCampo] = valor;
    } else {
      nuevosInstructores[indexInstructor].programacion[indexMes][campo] = valor;
    }
    setInstructores(nuevosInstructores);
    setFormData({ ...formData, instructores: nuevosInstructores });
  };
  // ===== FUNCIÓN DE VALIDACIÓN COMPLETA =====
const validarProgramacionCampesena = (instructores, curso) => {
  const errores = [];

  // 1. Validar que haya al menos un mes programado
  if (!instructores.some(inst => inst.programacion?.length > 0)) {
    errores.push('Debe programar al menos un mes para algún instructor');
  }

  // 2. Validar que todos los días estén dentro del rango del curso
  const fechaInicio = new Date(curso.fechas.inicio);
  const fechaFin = new Date(curso.fechas.fin);
  
  instructores.forEach((instructor, i) => {
    instructor.programacion?.forEach((mes, m) => {
      mes.dias?.forEach((dia, d) => {
        const fechaDia = new Date(dia);
        if (fechaDia < fechaInicio || fechaDia > fechaFin) {
          errores.push(`Instructor ${instructor.tipo}: El día ${dia} está fuera del rango del curso (${curso.fechas.inicio} - ${curso.fechas.fin})`);
        }
      });
    });
  });

  // 3. Validar que los meses programados no excedan la duración del curso
  const mesesCurso = Math.ceil((fechaFin - fechaInicio) / (1000 * 60 * 60 * 24 * 30));
  instructores.forEach((instructor, i) => {
    instructor.programacion?.forEach((mes) => {
      if (mes.mes > mesesCurso) {
        errores.push(`Instructor ${instructor.tipo}: El mes ${mes.mes} excede la duración del curso (${mesesCurso} meses)`);
      }
    });
  });

  // 4. Validar que no haya días repetidos entre instructores
  const todosLosDias = [];
  instructores.forEach((instructor, i) => {
    instructor.programacion?.forEach((mes) => {
      mes.dias?.forEach((dia) => {
        const diaStr = new Date(dia).toISOString().split('T')[0];
        const existe = todosLosDias.find(d => d.dia === diaStr);
        if (existe) {
          errores.push(`Conflicto de días: Instructor ${instructor.tipo} y ${existe.instructor} comparten el día ${diaStr}`);
        } else {
          todosLosDias.push({ dia: diaStr, instructor: instructor.tipo });
        }
      });
    });
  });

  // 5. Validar horarios por día
  instructores.forEach((instructor, i) => {
    instructor.programacion?.forEach((mes, m) => {
      const horaInicio = mes.horario.hora_inicio;
      const horaFin = mes.horario.hora_fin;
      
      // Convertir horas a minutos para comparar
      const [hInicio, mInicio] = horaInicio.split(':').map(Number);
      const [hFin, mFin] = horaFin.split(':').map(Number);
      const minutosInicio = hInicio * 60 + mInicio;
      const minutosFin = hFin * 60 + mFin;
      
      // Hora inicio < Hora fin
      if (minutosFin <= minutosInicio) {
        errores.push(`Instructor ${instructor.tipo}, mes ${mes.mes}: La hora fin debe ser mayor a la hora inicio`);
      }
      
      // Duración mínima 1 hora
      if (minutosFin - minutosInicio < 60) {
        errores.push(`Instructor ${instructor.tipo}, mes ${mes.mes}: La duración mínima por día es 1 hora`);
      }
      
      // Duración máxima 10 horas
      if (minutosFin - minutosInicio > 600) {
        errores.push(`Instructor ${instructor.tipo}, mes ${mes.mes}: La duración máxima por día es 10 horas`);
      }
      
      // Hora inicio mínima 06:00
      if (minutosInicio < 6 * 60) {
        errores.push(`Instructor ${instructor.tipo}, mes ${mes.mes}: La hora inicio no puede ser antes de las 06:00`);
      }
      
      // Hora fin máxima 22:00
      if (minutosFin > 22 * 60) {
        errores.push(`Instructor ${instructor.tipo}, mes ${mes.mes}: La hora fin no puede ser después de las 22:00`);
      }
    });
  });

  // 6. Validar horas totales del curso
  const duracionCursoHoras = curso.duracion_meses * 4 * 8; // Estimado: 4 semanas/mes * 8 horas/día
  let totalHoras = 0;
  
  instructores.forEach((instructor) => {
    instructor.programacion?.forEach((mes) => {
      const [hInicio, mInicio] = mes.horario.hora_inicio.split(':').map(Number);
      const [hFin, mFin] = mes.horario.hora_fin.split(':').map(Number);
      const horasPorDia = (hFin * 60 + mFin - (hInicio * 60 + mInicio)) / 60;
      totalHoras += (mes.dias?.length || 0) * horasPorDia;
    });
  });

  // Permitir un margen de error de 5 horas
  if (Math.abs(totalHoras - duracionCursoHoras) > 5) {
    errores.push(`La suma total de horas (${Math.round(totalHoras)}h) no coincide con la duración del curso (${duracionCursoHoras}h)`);
  }

  return errores;
};


  const actualizarDia = (indexInstructor, indexMes, indexDia, valor) => {
    const nuevosInstructores = [...instructores];
    nuevosInstructores[indexInstructor].programacion[indexMes].dias[indexDia] = valor;
    setInstructores(nuevosInstructores);
    setFormData({ ...formData, instructores: nuevosInstructores });
  };

  return (
    <div style={styles.container}>
      <h3 style={styles.title}>👨‍🏫 Instructores Campesena</h3>
      <p style={styles.subtitle}>Complete los datos de los 3 instructores (Técnico, Empresarial y Popular)</p>
      
      {instructores.map((instructor, idx) => (
        <div key={idx} style={styles.instructorBox}>
          <h4 style={styles.instructorTitle}>
            {instructor.tipo === 'Técnico' && '🔧'}
            {instructor.tipo === 'Empresarial' && '💼'}
            {instructor.tipo === 'Popular' && '👥'} Instructor {instructor.tipo}
          </h4>
          
          {/* Datos personales */}
          <div style={styles.row}>
            <div style={styles.half}>
              <label style={styles.label}>Tipo ID:</label>
              <select
                value={instructor.tipo_identificacion}
                onChange={(e) => actualizarCampo(idx, 'tipo_identificacion', e.target.value)}
                style={styles.select}
              >
                <option value="CC">CC</option>
                <option value="CE">CE</option>
                <option value="TI">TI</option>
                <option value="PAP">PAP</option>
                <option value="NIT">NIT</option>
              </select>
            </div>
            <div style={styles.half}>
              <label style={styles.label}>Identificación:</label>
              <input
                type="text"
                value={instructor.identificacion}
                onChange={(e) => actualizarCampo(idx, 'identificacion', e.target.value)}
                style={styles.input}
                placeholder="12345678"
              />
            </div>
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Nombre completo:</label>
            <input
              type="text"
              value={instructor.nombre}
              onChange={(e) => actualizarCampo(idx, 'nombre', e.target.value)}
              style={styles.input}
              placeholder="Nombre completo"
            />
          </div>

          <div style={styles.row}>
            <div style={styles.half}>
              <label style={styles.label}>Correo:</label>
              <input
                type="email"
                value={instructor.correo}
                onChange={(e) => actualizarCampo(idx, 'correo', e.target.value)}
                style={styles.input}
                placeholder="correo@ejemplo.com"
              />
            </div>
            <div style={styles.half}>
              <label style={styles.label}>Celular:</label>
              <input
                type="tel"
                value={instructor.celular}
                onChange={(e) => actualizarCampo(idx, 'celular', e.target.value)}
                style={styles.input}
                placeholder="3001234567"
              />
            </div>
          </div>

          {/* Programación por meses */}
          <h5 style={styles.programacionTitle}>📅 Programación mensual</h5>
          
          {instructor.programacion?.map((prog, pIdx) => (
            <div key={pIdx} style={styles.mesBox}>
              <h6 style={styles.mesTitle}>Mes {prog.mes}</h6>
              
              <div style={styles.row}>
                <div style={styles.half}>
                  <label style={styles.label}>Hora inicio:</label>
                  <input
                    type="time"
                    value={prog.horario.hora_inicio}
                    onChange={(e) => actualizarCampoProgramacion(idx, pIdx, 'horario.hora_inicio', e.target.value)}
                    style={styles.input}
                  />
                </div>
                <div style={styles.half}>
                  <label style={styles.label}>Hora fin:</label>
                  <input
                    type="time"
                    value={prog.horario.hora_fin}
                    onChange={(e) => actualizarCampoProgramacion(idx, pIdx, 'horario.hora_fin', e.target.value)}
                    style={styles.input}
                  />
                </div>
              </div>

              <label style={styles.label}>Días (formato YYYY-MM-DD):</label>
              <div style={styles.diasContainer}>
                {prog.dias?.map((dia, dIdx) => (
                  <div key={dIdx} style={styles.diaRow}>
                    <input
                      type="date"
                      value={dia}
                      onChange={(e) => actualizarDia(idx, pIdx, dIdx, e.target.value)}
                      style={styles.diaInput}
                    />
                    <button
                      type="button"
                      onClick={() => eliminarDia(idx, pIdx, dIdx)}
                      style={styles.removeButton}
                    >
                      ✕
                    </button>
                  </div>
                ))}
                <button
                  type="button"
                  onClick={() => agregarDia(idx, pIdx)}
                  style={styles.addButton}
                >
                  + Agregar día
                </button>
              </div>
            </div>
          ))}

          <button
            type="button"
            onClick={() => agregarMes(idx)}
            style={styles.addMesButton}
          >
            + Agregar mes
          </button>
        </div>
      ))}
    </div>
  );
};

const styles = {
  container: {
    width: '100%',
